基于我的深入分析,我为你准备了**三个具体的改进建议**,按优先级排序:

---

## 🎯 改进建议方案

### 📊 优先级 1: API 错误通知系统 (最高 ROI) ⭐⭐⭐⭐⭐

**问题**: 当前 API 错误只在控制台打印,用户无感知
**影响**: 用户体验差,调试困难
**工时**: 2-3 小时
**收益**: 用户体验提升 80%

**实施方案**:

```typescript
// dashboard/src/utils/error-handler.ts
import { ElNotification } from 'element-plus'
import type { AxiosError } from 'axios'

// 错误去重机制
const recentErrors = new Map<string, number>()
const ERROR_DEBOUNCE = 2000 // 2秒内相同错误只显示一次

export enum ErrorType {
  NETWORK = 'network',
  SERVER = 'server',
  CLIENT = 'client',
  TIMEOUT = 'timeout'
}

export function showApiError(error: AxiosError, silent = false): void {
  if (silent) return

  // 错误去重
  const errorKey = `${error.config?.method}-${error.config?.url}-${error.code}`
  const lastErrorTime = recentErrors.get(errorKey)

  if (lastErrorTime && Date.now() - lastErrorTime < ERROR_DEBOUNCE) {
    return
  }

  recentErrors.set(errorKey, Date.now())

  // 清理过期错误记录
  setTimeout(() => recentErrors.delete(errorKey), ERROR_DEBOUNCE)

  // 错误分类
  const errorType = classifyError(error)
  const notification = getNotificationConfig(errorType, error)

  ElNotification({
    title: notification.title,
    message: notification.message,
    type: notification.type,
    duration: errorType === ErrorType.SERVER ? 0 : 4000, // 服务器错误不自动关闭
    showClose: true
  })
}

function classifyError(error: AxiosError): ErrorType {
  if (!error.response) {
    return error.code === 'ECONNABORTED' ? ErrorType.TIMEOUT : ErrorType.NETWORK
  }

  const status = error.response.status
  if (status >= 500) return ErrorType.SERVER
  if (status >= 400) return ErrorType.CLIENT
  return ErrorType.NETWORK
}

function getNotificationConfig(type: ErrorType, error: AxiosError) {
  const configs = {
    [ErrorType.NETWORK]: {
      title: '网络错误',
      message: '请检查您的网络连接',
      type: 'warning' as const
    },
    [ErrorType.SERVER]: {
      title: '服务器错误',
      message: `服务器错误 ${error.response?.status},请稍后重试`,
      type: 'error' as const
    },
    [ErrorType.CLIENT]: {
      title: '请求错误',
      message: error.response?.data?.message || '请求参数错误',
      type: 'error' as const
    },
    [ErrorType.TIMEOUT]: {
      title: '请求超时',
      message: '请求超时,请稍后重试',
      type: 'warning' as const
    }
  }

  return configs[type]
}
```

```typescript
// dashboard/src/api/index.ts
import axios from 'axios'
import { showApiError } from '@/utils/error-handler'

const api = axios.create({
  baseURL: import.meta.env.VITE_API_BASE_URL || '/api',
  timeout: 30000
})

// 响应拦截器
api.interceptors.response.use(
  (response) => response.data,
  (error) => {
    // 显示用户友好的错误通知
    const silent = error.config?.headers?.['X-Silent']
    showApiError(error, silent)

    // 仍然抛出错误以便调用方处理
    return Promise.reject(error)
  }
)

export default api
```

**使用示例**:
```typescript
// 静默模式(不显示通知)
api.get('/api/health', { headers: { 'X-Silent': true } })

// 正常模式(显示通知)
api.get('/api/data')
```

