### 🛡️ 优先级 3: Vue 错误边界 (稳定性保障) ⭐⭐⭐

**问题**: 组件错误可能导致整个应用崩溃
**工时**: 2 小时
**收益**: 提升应用稳定性,避免白屏

**实施方案**:

```typescript
// dashboard/src/utils/error-boundary.ts
import { ElNotification } from 'element-plus'
import type { App } from 'vue'

export function setupErrorBoundary(app: App) {
  // Vue 错误处理
  app.config.errorHandler = (err, instance, info) => {
    console.error('Vue Error:', err, info)

    ElNotification({
      title: '页面错误',
      message: `发生错误: ${err.message}`,
      type: 'error',
      duration: 0,
      showClose: true
    })
  }

  // 全局未捕获错误
  window.addEventListener('error', (event) => {
    console.error('Global Error:', event.error)

    ElNotification({
      title: '系统错误',
      message: '发生未预期的错误,请刷新页面',
      type: 'error',
      duration: 0
    })
  })

  // Promise 拒绝错误
  window.addEventListener('unhandledrejection', (event) => {
    console.error('Unhandled Rejection:', event.reason)

    ElNotification({
      title: '异步操作失败',
      message: event.reason?.message || '未知错误',
      type: 'warning',
      duration: 5000
    })
  })
}
```

**在 main.ts 中初始化**:
```typescript
import { createApp } from 'vue'
import App from './App.vue'
import { setupErrorBoundary } from './utils/error-boundary'

const app = createApp(App)

// 设置错误边界
setupErrorBoundary(app)

app.mount('#app')
```

